const express = require('express');
const bodyParser = require('body-parser');
const dotenv = require('dotenv');
const redis = require('redis');
const twilio = require('twilio');

dotenv.config();

const app = express();
app.use(bodyParser.json());

// --- Redis Client Setup ---
const redisClient = redis.createClient({
  url: process.env.REDIS_URL || 'redis://localhost:6379'
});

redisClient.on('connect', () => console.log('Connected to Redis!'));
redisClient.on('error', (err) => console.error('Redis Client Error', err));

// Connect to Redis
(async () => {
  await redisClient.connect();
})();


// --- Twilio Client Setup ---
const twilioClient = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);
const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER;

// --- Constants ---
const CODE_EXPIRATION_SECONDS = 10 * 60; // 10 minutes
const MAX_ATTEMPTS = 10;
const REDIS_PREFIX = '2fa:';

// --- Helper Functions ---

/**
 * Generates a random 6-digit code.
 * @returns {string} The 6-digit code.
 */
function generateSixDigitCode() {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

/**
 * Sends an SMS message using Twilio.
 * @param {string} toPhoneNumber - The recipient's phone number.
 * @param {string} message - The message body.
 */
async function sendSms(toPhoneNumber, message) {
  try {
    await twilioClient.messages.create({
      body: message,
      from: twilioPhoneNumber,
      to: toPhoneNumber,
    });
    console.log(`SMS sent to ${toPhoneNumber}`);
  } catch (error) {
    console.error(`Error sending SMS to ${toPhoneNumber}:`, error);
    throw new Error('Failed to send SMS.');
  }
}

// --- Express Endpoints ---

/**
 * POST /request-2fa
 * Generates a 2FA code, stores it in Redis, and sends it via SMS.
 * Requires `userId` and `userPhoneNumber` in the request body.
 * (In a real app, `userPhoneNumber` would come from the authenticated user's profile)
 */
app.post('/request-2fa', async (req, res) => {
  const { userId, userPhoneNumber } = req.body;

  if (!userId || !userPhoneNumber) {
    return res.status(400).json({ success: false, message: 'userId and userPhoneNumber are required.' });
  }

  const code = generateSixDigitCode();
  const redisKey = `${REDIS_PREFIX}${userId}`;

  try {
    // Store code, attempts, and lockout status in a Redis HASH
    await redisClient.hSet(redisKey, {
      code: code,
      attempts: 0,
      locked: 'false'
    });
    await redisClient.expire(redisKey, CODE_EXPIRATION_SECONDS);

    const message = `Your 2FA code is: ${code}. It expires in 10 minutes.`;
    await sendSms(userPhoneNumber, message);

    res.status(200).json({
      success: true,
      message: '2FA code sent to your phone. Please verify within 10 minutes.',
      expiresAt: Date.now() + CODE_EXPIRATION_SECONDS * 1000
    });
  } catch (error) {
    console.error('Error requesting 2FA:', error);
    res.status(500).json({ success: false, message: 'Failed to request 2FA.', error: error.message });
  }
});

/**
 * POST /verify-2fa
 * Verifies the 2FA code provided by the user.
 * Requires `userId` and `code` in the request body.
 */
app.post('/verify-2fa', async (req, res) => {
  const { userId, code } = req.body;

  if (!userId || !code) {
    return res.status(400).json({ success: false, message: 'userId and code are required.' });
  }

  const redisKey = `${REDIS_PREFIX}${userId}`;

  try {
    const twoFaData = await redisClient.hGetAll(redisKey);

    if (Object.keys(twoFaData).length === 0) {
      return res.status(400).json({ success: false, message: 'No active 2FA code found or it has expired. Please request a new one.' });
    }

    let { code: storedCode, attempts: currentAttempts, locked: isLocked } = twoFaData;
    currentAttempts = parseInt(currentAttempts, 10);
    isLocked = isLocked === 'true';

    if (isLocked) {
      return res.status(403).json({ success: false, message: 'Account is locked due to too many failed attempts. Please request a new code.' });
    }

    if (code === storedCode) {
      await redisClient.del(redisKey); // Invalidate the code after successful verification
      res.status(200).json({ success: true, message: '2FA verification successful! Access granted.' });
    } else {
      currentAttempts++;

      if (currentAttempts >= MAX_ATTEMPTS) {
        await redisClient.hSet(redisKey, { attempts: currentAttempts, locked: 'true' });
        // Optionally, expire the key sooner or keep it locked for a longer period
        await redisClient.expire(redisKey, 3600); // Lock for an hour
        return res.status(403).json({ success: false, message: `Invalid code. Too many attempts. Your 2FA is locked. Please request a new code to unlock.` });
      } else {
        await redisClient.hSet(redisKey, { attempts: currentAttempts });
        // Keep the original expiration time
        const ttl = await redisClient.ttl(redisKey);
        await redisClient.expire(redisKey, ttl); // Re-set expiration to ensure it doesn't get removed by hSet implicitly

        res.status(401).json({
          success: false,
          message: `Invalid 2FA code. You have ${MAX_ATTEMPTS - currentAttempts} attempts remaining.`
        });
      }
    }
  } catch (error) {
    console.error('Error verifying 2FA:', error);
    res.status(500).json({ success: false, message: 'Failed to verify 2FA.', error: error.message });
  }
});

